parameters.new_string:
  it('should paginate with large page size', () => {
    const result = paginate(items, 1, 100);
    expect(result.items).toEqual(items);
    expect(result.totalPages).toBe(1);
  });

  it('should not produce duplicate items across consecutive pages', () => {
    const allItems = Array.from({ length: 10 }, (_, i) => i + 1);
    const pageSize = 3;
    const collected: number[] = [];

    const totalPages = Math.ceil(allItems.length / pageSize);
    for (let p = 1; p <= totalPages; p++) {
      const result = paginate(allItems, p, pageSize);
      collected.push(...result.items);
    }

    // Every item should appear exactly once — no duplicates, no gaps
    expect(collected).toEqual(allItems);
  });

  it('should return correct items for page 2', () => {
    const result = paginate(items, 2, 3);
    expect(result.items).toEqual([4, 5, 6]);
    expect(result.hasPrevious).toBe(true);
    expect(result.hasNext).toBe(true);
  });
});

